mapper.select:
SELECT s.id, s.series_name AS seriesName, LEFT(COALESCE(s.background, ''), 140) AS background, s.status, s.created_at AS createdAt, s.updated_at AS updatedAt, COUNT(r.id) AS roleCount FROM series s LEFT JOIN role r ON r.series_id = s.id AND r.is_deleted = 0 WHERE s.is_deleted = 0
AND s.user_id = #{userId}
GROUP BY s.id, s.series_name, s.background, s.status, s.created_at, s.updated_at ORDER BY s.created_at DESC LIMIT #{limit} OFFSET #{offset}
